import React, { useState, useEffect, useCallback } from 'react';
import { useAuth } from '../App';
import api from '../api';

// ── Icon helper ───────────────────────────────────────────────────────────────
const I = ({ c, style }) => <i className={`fa-solid ${c}`} style={style} />;

const ADMIN_TABS = [
  { key: 'overview',      icon: 'fa-chart-line',     label: 'Overview'     },
  { key: 'users',         icon: 'fa-users',           label: 'Users'        },
  { key: 'hospitals',     icon: 'fa-hospital',        label: 'Hospitals'    },
  { key: 'deficiencies',  icon: 'fa-leaf',            label: 'Deficiencies' },
];

const ROLES = ['USER', 'ADMIN'];
const BLOOD_GROUPS = ['A+','A-','B+','B-','AB+','AB-','O+','O-'];
const HOSPITAL_TYPES = ['government','private','mission','clinic'];
const DEFICIENCY_LIST = [
  { id:'iron',       icon:'fa-droplet',       name:'Iron Deficiency Anaemia',        color:'#dc2626', stat:'~35% of Kenyan women', symptoms:20, foods:7  },
  { id:'vitamin_a',  icon:'fa-eye',           name:'Vitamin A Deficiency',           color:'#d97706', stat:'~35% of under-5s',     symptoms:10, foods:8  },
  { id:'vitamin_d',  icon:'fa-sun',           name:'Vitamin D Deficiency',           color:'#f59e0b', stat:'Common indoors',        symptoms:12, foods:6  },
  { id:'vitamin_b12',icon:'fa-brain',         name:'Vitamin B12 Deficiency',         color:'#0891b2', stat:'Rising vegetarianism',  symptoms:13, foods:6  },
  { id:'folate',     icon:'fa-seedling',      name:'Folate Deficiency',              color:'#16a34a', stat:'Critical in pregnancy', symptoms:11, foods:7  },
  { id:'iodine',     icon:'fa-shield-halved', name:'Iodine Deficiency',             color:'#7c3aed', stat:'Rift Valley belt',      symptoms:14, foods:5  },
  { id:'zinc',       icon:'fa-shield',        name:'Zinc Deficiency',                color:'#0f766e', stat:'26% child stunting',    symptoms:11, foods:6  },
  { id:'calcium',    icon:'fa-bone',          name:'Calcium Deficiency',             color:'#64748b', stat:'Low dairy intake',      symptoms:12, foods:6  },
  { id:'vitamin_c',  icon:'fa-circle-dot',    name:'Vitamin C Deficiency',           color:'#ea580c', stat:'Low fruit intake',      symptoms:10, foods:6  },
  { id:'protein',    icon:'fa-dumbbell',      name:'Protein Deficiency',             color:'#b45309', stat:'11% of under-5s',       symptoms:12, foods:7  },
];

// ── Modal ─────────────────────────────────────────────────────────────────────
function Modal({ title, onClose, children }) {
  return (
    <div style={{ position:'fixed',inset:0,background:'rgba(0,0,0,0.45)',zIndex:1000,display:'flex',alignItems:'center',justifyContent:'center',padding:'1rem' }}
         onClick={e => e.target === e.currentTarget && onClose()}>
      <div style={{ background:'#fff',borderRadius:16,width:'100%',maxWidth:520,maxHeight:'90vh',overflow:'auto',boxShadow:'0 20px 60px rgba(0,0,0,0.25)' }}>
        <div style={{ padding:'1.25rem 1.5rem',borderBottom:'1px solid #e5e7eb',display:'flex',alignItems:'center',justifyContent:'space-between',position:'sticky',top:0,background:'#fff',zIndex:1 }}>
          <h3 style={{ fontSize:'1rem',fontWeight:700,fontFamily:'Outfit,sans-serif' }}>{title}</h3>
          <button onClick={onClose} style={{ background:'none',border:'none',cursor:'pointer',color:'#6b7280',fontSize:'1.1rem',width:28,height:28,borderRadius:6,display:'flex',alignItems:'center',justifyContent:'center' }}>
            <I c="fa-xmark" />
          </button>
        </div>
        <div style={{ padding:'1.5rem' }}>{children}</div>
      </div>
    </div>
  );
}

// ── Overview ──────────────────────────────────────────────────────────────────
function Overview() {
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);
  const [err, setErr] = useState('');

  const load = useCallback(() => {
    setLoading(true);
    api.get('/api/admin/stats')
      .then(r => { setStats(r.data); setLoading(false); })
      .catch(() => { setErr('Failed to load stats. Is the backend running?'); setLoading(false); });
  }, []);
  useEffect(() => { load(); }, [load]);

  if (loading) return <div style={{textAlign:'center',padding:'3rem'}}><span className="spinner" style={{margin:'0 auto',display:'block'}}/></div>;
  if (err)    return <div className="alert alert-error">{err} <button className="btn btn-ghost btn-sm" onClick={load} style={{marginLeft:8}}>Retry</button></div>;

  const STAT_CARDS = [
    { label:'Registered Users',  value: stats.users,     color:'#16a34a', icon:'fa-users'       },
    { label:'AI Analyses Run',   value: stats.analyses,  color:'#0891b2', icon:'fa-stethoscope' },
    { label:'Hospitals Listed',  value: stats.hospitals, color:'#d97706', icon:'fa-hospital'    },
  ];

  return (
    <div style={{display:'flex',flexDirection:'column',gap:'1rem'}}>
      {/* Stat cards */}
      <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fit,minmax(180px,1fr))',gap:12}}>
        {STAT_CARDS.map(c => (
          <div key={c.label} className="card" style={{textAlign:'center',border:`1px solid ${c.color}20`,padding:'1.25rem'}}>
            <I c={c.icon} style={{fontSize:'1.6rem',color:c.color,marginBottom:8,display:'block'}}/>
            <div style={{fontSize:'2rem',fontWeight:800,fontFamily:'Fraunces,serif',color:c.color,lineHeight:1}}>{c.value}</div>
            <div style={{fontSize:'0.78rem',color:'#6b7280',fontWeight:600,marginTop:4}}>{c.label}</div>
          </div>
        ))}
      </div>

      {/* Recent analyses — live from DB */}
      <div className="card">
        <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:'1rem'}}>
          <h4 style={{fontFamily:'Outfit,sans-serif',fontWeight:700,fontSize:'0.95rem'}}>
            <I c="fa-clock-rotate-left" style={{marginRight:8,color:'#16a34a'}}/>Recent Analyses
          </h4>
          <button onClick={load} className="btn btn-ghost btn-sm"><I c="fa-rotate" style={{marginRight:4}}/>Refresh</button>
        </div>
        {stats.recent?.length ? (
          <div style={{display:'flex',flexDirection:'column',gap:8}}>
            {stats.recent.map(r => (
              <div key={r.id} style={{padding:'10px 12px',background:'#f9fafb',borderRadius:8,border:'1px solid #f1f1f1'}}>
                <div style={{display:'flex',justifyContent:'space-between',marginBottom:4,flexWrap:'wrap',gap:4}}>
                  <span style={{fontSize:'0.8rem',fontWeight:600,color:'#374151'}}>
                    <I c="fa-user" style={{marginRight:5,color:'#6b7280'}}/>{r.user_name}
                    <span style={{color:'#9ca3af',fontWeight:400,marginLeft:4}}>({r.email})</span>
                  </span>
                  <span style={{fontSize:'0.72rem',color:'#6b7280'}}>{new Date(r.timestamp).toLocaleString('en-KE')}</span>
                </div>
                <div style={{fontSize:'0.82rem',color:'#374151',fontStyle:'italic',marginBottom:6}}>
                  "{r.symptoms.substring(0,90)}{r.symptoms.length>90?'...':''}"
                </div>
                {r.results?.length > 0 && (
                  <div style={{display:'flex',flexWrap:'wrap',gap:4}}>
                    {r.results.slice(0,3).map(res => (
                      <span key={res.id} style={{background:`${res.color}12`,color:res.color,border:`1px solid ${res.color}30`,borderRadius:12,padding:'1px 8px',fontSize:'0.7rem',fontWeight:700}}>
                        {res.name} · {res.confidence}%
                      </span>
                    ))}
                  </div>
                )}
              </div>
            ))}
          </div>
        ) : <p style={{color:'#6b7280',fontSize:'0.875rem'}}>No analyses yet.</p>}
      </div>

      {/* System status — checks live /api/health */}
      <SystemStatus />
    </div>
  );
}

function SystemStatus() {
  const [health, setHealth] = useState(null);
  useEffect(() => {
    api.get('/api/health')
      .then(r => setHealth({ ok:true, ...r.data }))
      .catch(() => setHealth({ ok:false }));
  }, []);

  const rows = health ? [
    { label:'Flask API',            status: health.ok ? 'Online' : 'Offline',  ok: health.ok },
    { label:'SQLite Database',      status: health.ok ? `Connected (${health.registered_users} users)` : 'Disconnected', ok: health.ok },
    { label:'AI Engine (JS + Py)',  status:'Active',  ok:true },
    { label:'OpenStreetMap Tiles',  status:'Free — no API key needed',  ok:true },
    { label:'JWT Auth',             status:'Enabled (12h expiry)',  ok:true },
  ] : [];

  return (
    <div className="card">
      <h4 style={{fontFamily:'Outfit,sans-serif',fontWeight:700,fontSize:'0.95rem',marginBottom:'1rem'}}>
        <I c="fa-server" style={{marginRight:8,color:'#16a34a'}}/>System Status
      </h4>
      {!health ? <div style={{textAlign:'center'}}><span className="spinner" style={{margin:'0 auto',display:'block'}}/></div> : (
        <div style={{display:'flex',flexDirection:'column',gap:0}}>
          {rows.map(r => (
            <div key={r.label} style={{display:'flex',justifyContent:'space-between',alignItems:'center',padding:'9px 0',borderBottom:'1px solid #f3f4f6'}}>
              <span style={{fontSize:'0.875rem',color:'#374151'}}>{r.label}</span>
              <span style={{fontSize:'0.78rem',fontWeight:700,color:r.ok?'#16a34a':'#dc2626',display:'flex',alignItems:'center',gap:5}}>
                <I c={r.ok?'fa-circle-check':'fa-circle-xmark'}/> {r.status}
              </span>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

// ── Users ─────────────────────────────────────────────────────────────────────
function Users() {
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [editUser, setEditUser] = useState(null);    // user object to edit
  const [detailUser, setDetailUser] = useState(null);// user + analyses detail
  const [detailLoading, setDetailLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [msg, setMsg] = useState('');
  const [confirmDelete, setConfirmDelete] = useState(null);

  const load = useCallback(() => {
    setLoading(true);
    api.get(`/api/admin/users${search ? `?q=${encodeURIComponent(search)}` : ''}`)
      .then(r => { setUsers(r.data); setLoading(false); })
      .catch(() => setLoading(false));
  }, [search]);
  useEffect(() => { load(); }, [load]);

  const openDetail = async (uid) => {
    setDetailLoading(true);
    try {
      const r = await api.get(`/api/admin/users/${uid}`);
      setDetailUser(r.data);
    } catch {}
    setDetailLoading(false);
  };

  const saveUser = async (form) => {
    setSaving(true); setMsg('');
    try {
      await api.put(`/api/admin/users/${form.id}`, form);
      setMsg('User updated successfully');
      setEditUser(null);
      load();
    } catch (e) {
      setMsg(e.response?.data?.error || 'Save failed');
    }
    setSaving(false);
  };

  const deleteUser = async (uid) => {
    try {
      await api.delete(`/api/admin/users/${uid}`);
      setConfirmDelete(null);
      load();
    } catch (e) {
      alert(e.response?.data?.error || 'Delete failed');
    }
  };

  return (
    <div>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:'1rem',gap:8,flexWrap:'wrap'}}>
        <h4 style={{fontFamily:'Outfit,sans-serif',fontWeight:700,fontSize:'0.95rem'}}>
          <I c="fa-users" style={{marginRight:8,color:'#16a34a'}}/>{users.length} Users
        </h4>
        <div style={{display:'flex',gap:8,alignItems:'center'}}>
          <div style={{position:'relative'}}>
            <I c="fa-magnifying-glass" style={{position:'absolute',left:10,top:'50%',transform:'translateY(-50%)',color:'#9ca3af',fontSize:'0.8rem'}}/>
            <input className="form-input" value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search name or email..." style={{paddingLeft:30,width:220}}/>
          </div>
          <button onClick={load} className="btn btn-ghost btn-sm"><I c="fa-rotate" style={{marginRight:4}}/>Refresh</button>
        </div>
      </div>

      {msg && <div className="alert alert-success" style={{marginBottom:'1rem'}}>{msg}</div>}

      {loading ? <div style={{textAlign:'center',padding:'2rem'}}><span className="spinner" style={{margin:'0 auto',display:'block'}}/></div> : (
        <div style={{background:'#fff',borderRadius:12,border:'1px solid #e5e7eb',overflow:'hidden'}}>
          <table style={{width:'100%',borderCollapse:'collapse'}}>
            <thead style={{background:'#f9fafb'}}>
              <tr>
                {['User','Email','Role','Analyses','Last Active','Actions'].map(h=>(
                  <th key={h} style={{padding:'10px 14px',textAlign:'left',fontSize:'0.7rem',fontWeight:700,color:'#6b7280',textTransform:'uppercase',letterSpacing:'0.05em',borderBottom:'1px solid #e5e7eb'}}>
                    {h}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {users.map((u,i) => (
                <tr key={u.id} style={{background:i%2===0?'white':'#fafafa',transition:'background 0.15s'}}
                    onMouseEnter={e=>e.currentTarget.style.background='#f0fdf4'}
                    onMouseLeave={e=>e.currentTarget.style.background=i%2===0?'white':'#fafafa'}>
                  <td style={{padding:'10px 14px',borderBottom:'1px solid #f1f1f1'}}>
                    <div style={{display:'flex',alignItems:'center',gap:8}}>
                      <div style={{width:30,height:30,borderRadius:'50%',background:u.role==='ADMIN'?'linear-gradient(135deg,#dc2626,#b91c1c)':'linear-gradient(135deg,#16a34a,#15803d)',display:'flex',alignItems:'center',justifyContent:'center',color:'white',fontSize:'0.8rem',fontWeight:700,flexShrink:0}}>
                        {(u.name||'U')[0].toUpperCase()}
                      </div>
                      <span style={{fontSize:'0.875rem',fontWeight:600}}>{u.name}</span>
                    </div>
                  </td>
                  <td style={{padding:'10px 14px',fontSize:'0.8rem',color:'#6b7280',borderBottom:'1px solid #f1f1f1'}}>{u.email}</td>
                  <td style={{padding:'10px 14px',borderBottom:'1px solid #f1f1f1'}}>
                    <span style={{background:u.role==='ADMIN'?'#fef2f2':'#f0fdf4',color:u.role==='ADMIN'?'#dc2626':'#16a34a',borderRadius:8,padding:'2px 8px',fontSize:'0.7rem',fontWeight:700}}>
                      {u.role}
                    </span>
                  </td>
                  <td style={{padding:'10px 14px',fontSize:'0.875rem',color:'#374151',fontWeight:600,borderBottom:'1px solid #f1f1f1'}}>{u.analyses_count}</td>
                  <td style={{padding:'10px 14px',fontSize:'0.75rem',color:'#6b7280',borderBottom:'1px solid #f1f1f1'}}>
                    {u.last_active ? new Date(u.last_active).toLocaleDateString('en-KE') : <span style={{color:'#d1d5db'}}>Never</span>}
                  </td>
                  <td style={{padding:'10px 14px',borderBottom:'1px solid #f1f1f1'}}>
                    <div style={{display:'flex',gap:4}}>
                      <button onClick={()=>openDetail(u.id)} title="View details" style={{background:'#f0fdf4',border:'1px solid #bbf7d0',color:'#16a34a',borderRadius:6,padding:'4px 8px',cursor:'pointer',fontSize:'0.75rem'}}>
                        <I c="fa-eye"/>
                      </button>
                      <button onClick={()=>setEditUser({...u,password:''})} title="Edit user" style={{background:'#eff6ff',border:'1px solid #bfdbfe',color:'#1d4ed8',borderRadius:6,padding:'4px 8px',cursor:'pointer',fontSize:'0.75rem'}}>
                        <I c="fa-pen"/>
                      </button>
                      <button onClick={()=>setConfirmDelete(u)} title="Delete user" style={{background:'#fef2f2',border:'1px solid #fca5a5',color:'#dc2626',borderRadius:6,padding:'4px 8px',cursor:'pointer',fontSize:'0.75rem'}}>
                        <I c="fa-trash"/>
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {users.length === 0 && <div style={{textAlign:'center',padding:'2rem',color:'#6b7280',fontSize:'0.875rem'}}>No users found.</div>}
        </div>
      )}

      {/* Edit User Modal */}
      {editUser && (
        <Modal title={`Edit User — ${editUser.name}`} onClose={()=>setEditUser(null)}>
          <UserForm user={editUser} saving={saving} msg={msg} onSave={saveUser} onCancel={()=>setEditUser(null)}/>
        </Modal>
      )}

      {/* User Detail Modal */}
      {(detailUser || detailLoading) && (
        <Modal title="User Details" onClose={()=>setDetailUser(null)}>
          {detailLoading ? <div style={{textAlign:'center',padding:'2rem'}}><span className="spinner" style={{margin:'0 auto',display:'block'}}/></div> : detailUser && (
            <UserDetail data={detailUser} onEdit={u=>{setDetailUser(null);setEditUser({...u,password:''}); }}/>
          )}
        </Modal>
      )}

      {/* Confirm Delete */}
      {confirmDelete && (
        <Modal title="Confirm Delete" onClose={()=>setConfirmDelete(null)}>
          <div style={{textAlign:'center'}}>
            <I c="fa-triangle-exclamation" style={{fontSize:'2.5rem',color:'#dc2626',marginBottom:12,display:'block'}}/>
            <p style={{fontSize:'0.875rem',color:'#374151',marginBottom:16}}>
              Delete <strong>{confirmDelete.name}</strong> ({confirmDelete.email})? This will also delete all their analyses. This cannot be undone.
            </p>
            <div style={{display:'flex',gap:8,justifyContent:'center'}}>
              <button className="btn btn-ghost" onClick={()=>setConfirmDelete(null)}>Cancel</button>
              <button className="btn btn-danger" onClick={()=>deleteUser(confirmDelete.id)}>
                <I c="fa-trash" style={{marginRight:6}}/>Delete Permanently
              </button>
            </div>
          </div>
        </Modal>
      )}
    </div>
  );
}

function UserForm({ user, saving, msg, onSave, onCancel }) {
  const [form, setForm] = useState({ ...user });
  const set = k => e => setForm(f=>({...f,[k]:e.target.value}));
  return (
    <div>
      {msg && <div className={`alert ${msg.includes('success')?'alert-success':'alert-error'}`} style={{marginBottom:'1rem'}}>{msg}</div>}
      <div className="form-group">
        <label className="form-label">Full Name</label>
        <input className="form-input" value={form.name||''} onChange={set('name')} required/>
      </div>
      <div className="form-group">
        <label className="form-label">Email</label>
        <input type="email" className="form-input" value={form.email||''} onChange={set('email')} required/>
      </div>
      <div className="grid-2">
        <div className="form-group">
          <label className="form-label">Role</label>
          <select className="form-input" value={form.role||'USER'} onChange={set('role')}>
            {ROLES.map(r=><option key={r}>{r}</option>)}
          </select>
        </div>
        <div className="form-group">
          <label className="form-label">Age</label>
          <input type="number" className="form-input" value={form.age||''} onChange={set('age')} min="1" max="120"/>
        </div>
      </div>
      <div className="grid-2">
        <div className="form-group">
          <label className="form-label">Blood Group</label>
          <select className="form-input" value={form.blood_group||''} onChange={set('blood_group')}>
            <option value="">Unknown</option>
            {BLOOD_GROUPS.map(b=><option key={b}>{b}</option>)}
          </select>
        </div>
        <div className="form-group">
          <label className="form-label">New Password <span style={{color:'#9ca3af',fontWeight:400}}>(leave blank to keep)</span></label>
          <input type="password" className="form-input" value={form.password||''} onChange={set('password')} placeholder="••••••" minLength={6}/>
        </div>
      </div>
      <div className="form-group">
        <label className="form-label">Allergies</label>
        <input className="form-input" value={form.allergies||''} onChange={set('allergies')}/>
      </div>
      <div className="form-group">
        <label className="form-label">Chronic Conditions</label>
        <input className="form-input" value={form.chronic_conditions||''} onChange={set('chronic_conditions')}/>
      </div>
      <div style={{display:'flex',gap:8,marginTop:'0.5rem'}}>
        <button className="btn btn-ghost" onClick={onCancel} style={{flex:1,justifyContent:'center'}}>Cancel</button>
        <button className="btn btn-primary" onClick={()=>onSave(form)} disabled={saving} style={{flex:2,justifyContent:'center'}}>
          {saving ? <><span className="spinner" style={{width:14,height:14}}/> Saving...</> : <><I c="fa-floppy-disk" style={{marginRight:6}}/>Save Changes</>}
        </button>
      </div>
    </div>
  );
}

function UserDetail({ data, onEdit }) {
  const { user, analyses } = data;
  return (
    <div>
      <div style={{display:'flex',alignItems:'center',gap:12,marginBottom:'1.25rem',padding:'1rem',background:'#f9fafb',borderRadius:12,border:'1px solid #e5e7eb'}}>
        <div style={{width:48,height:48,borderRadius:'50%',background:user.role==='ADMIN'?'linear-gradient(135deg,#dc2626,#b91c1c)':'linear-gradient(135deg,#16a34a,#15803d)',display:'flex',alignItems:'center',justifyContent:'center',color:'white',fontSize:'1.2rem',fontWeight:700,flexShrink:0}}>
          {(user.name||'U')[0].toUpperCase()}
        </div>
        <div style={{flex:1}}>
          <div style={{fontWeight:700,fontSize:'1rem'}}>{user.name}</div>
          <div style={{fontSize:'0.8rem',color:'#6b7280'}}>{user.email}</div>
          <div style={{display:'flex',gap:6,marginTop:4,flexWrap:'wrap'}}>
            <span style={{background:user.role==='ADMIN'?'#fef2f2':'#f0fdf4',color:user.role==='ADMIN'?'#dc2626':'#16a34a',borderRadius:8,padding:'1px 8px',fontSize:'0.7rem',fontWeight:700}}>{user.role}</span>
            {user.blood_group && <span style={{background:'#fef2f2',color:'#dc2626',borderRadius:8,padding:'1px 8px',fontSize:'0.7rem',fontWeight:700}}>{user.blood_group}</span>}
            {user.age && <span style={{background:'#f1f5f9',color:'#475569',borderRadius:8,padding:'1px 8px',fontSize:'0.7rem',fontWeight:600}}>Age {user.age}</span>}
          </div>
        </div>
        <button className="btn btn-outline btn-sm" onClick={()=>onEdit(user)}><I c="fa-pen" style={{marginRight:5}}/>Edit</button>
      </div>
      {user.allergies && <div style={{marginBottom:8,fontSize:'0.82rem',color:'#d97706'}}><I c="fa-triangle-exclamation" style={{marginRight:5}}/>Allergies: {user.allergies}</div>}
      {user.chronic_conditions && <div style={{marginBottom:'1rem',fontSize:'0.82rem',color:'#0891b2'}}><I c="fa-notes-medical" style={{marginRight:5}}/>Conditions: {user.chronic_conditions}</div>}
      <div style={{fontSize:'0.8rem',color:'#6b7280',marginBottom:'0.75rem',fontWeight:600}}>
        <I c="fa-stethoscope" style={{marginRight:6}}/>Analysis History ({analyses.length})
      </div>
      {analyses.length === 0 ? (
        <p style={{color:'#9ca3af',fontSize:'0.82rem'}}>No analyses yet.</p>
      ) : analyses.map(a => (
        <div key={a.id} style={{padding:'8px 12px',background:'#f9fafb',border:'1px solid #e5e7eb',borderRadius:8,marginBottom:8}}>
          <div style={{fontSize:'0.72rem',color:'#6b7280',marginBottom:3}}>{new Date(a.timestamp).toLocaleString('en-KE')}</div>
          <div style={{fontSize:'0.82rem',fontStyle:'italic',color:'#374151',marginBottom:5}}>"{a.symptoms.substring(0,80)}..."</div>
          <div style={{display:'flex',flexWrap:'wrap',gap:4}}>
            {(a.results||[]).map(r=>(
              <span key={r.id} style={{background:`${r.color}12`,color:r.color,border:`1px solid ${r.color}30`,borderRadius:10,padding:'1px 7px',fontSize:'0.68rem',fontWeight:700}}>
                {r.name} {r.confidence}%
              </span>
            ))}
          </div>
        </div>
      ))}
      <div style={{marginTop:'1rem',fontSize:'0.72rem',color:'#9ca3af'}}>
        <I c="fa-calendar" style={{marginRight:4}}/>Joined {user.created_at ? new Date(user.created_at).toLocaleDateString('en-KE') : 'unknown'}
      </div>
    </div>
  );
}

// ── Hospitals ─────────────────────────────────────────────────────────────────
const BLANK_HOSPITAL = { name:'',address:'',latitude:'',longitude:'',phone:'',type:'government',services:'',emergency:false };

function Hospitals() {
  const [hospitals, setHospitals] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [editH, setEditH] = useState(null);   // null=closed, {}=new, obj=edit
  const [saving, setSaving] = useState(false);
  const [msg, setMsg] = useState('');
  const [confirmDel, setConfirmDel] = useState(null);

  const load = useCallback(() => {
    setLoading(true);
    api.get(`/api/hospitals${search?`?q=${encodeURIComponent(search)}`:''}`)
      .then(r=>{setHospitals(r.data);setLoading(false);})
      .catch(()=>setLoading(false));
  },[search]);
  useEffect(()=>{load();},[load]);

  const saveHospital = async (form) => {
    setSaving(true); setMsg('');
    try {
      const payload = {
        ...form,
        services: typeof form.services === 'string'
          ? form.services.split(',').map(s=>s.trim()).filter(Boolean)
          : form.services,
        emergency: !!form.emergency
      };
      if (form.id) {
        await api.put(`/api/hospitals/${form.id}`, payload);
        setMsg('Hospital updated');
      } else {
        await api.post('/api/hospitals', payload);
        setMsg('Hospital added');
      }
      setEditH(null); load();
    } catch(e) { setMsg(e.response?.data?.error||'Save failed'); }
    setSaving(false);
  };

  const deleteH = async (hid) => {
    try { await api.delete(`/api/hospitals/${hid}`); setConfirmDel(null); load(); }
    catch(e) { alert(e.response?.data?.error||'Delete failed'); }
  };

  return (
    <div>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:'1rem',gap:8,flexWrap:'wrap'}}>
        <h4 style={{fontFamily:'Outfit,sans-serif',fontWeight:700,fontSize:'0.95rem'}}>
          <I c="fa-hospital" style={{marginRight:8,color:'#16a34a'}}/>{hospitals.length} Hospitals
        </h4>
        <div style={{display:'flex',gap:8}}>
          <div style={{position:'relative'}}>
            <I c="fa-magnifying-glass" style={{position:'absolute',left:10,top:'50%',transform:'translateY(-50%)',color:'#9ca3af',fontSize:'0.8rem'}}/>
            <input className="form-input" value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search hospitals..." style={{paddingLeft:30,width:200}}/>
          </div>
          <button className="btn btn-primary btn-sm" onClick={()=>setEditH({...BLANK_HOSPITAL})}>
            <I c="fa-plus" style={{marginRight:5}}/>Add Hospital
          </button>
        </div>
      </div>

      {msg && <div className="alert alert-success" style={{marginBottom:'1rem'}}>{msg}</div>}

      {loading ? <div style={{textAlign:'center',padding:'2rem'}}><span className="spinner" style={{margin:'0 auto',display:'block'}}/></div> : (
        <div style={{background:'#fff',borderRadius:12,border:'1px solid #e5e7eb',overflow:'hidden'}}>
          <table style={{width:'100%',borderCollapse:'collapse'}}>
            <thead style={{background:'#f9fafb'}}>
              <tr>
                {['Name & Address','Type','Phone','Emergency','Actions'].map(h=>(
                  <th key={h} style={{padding:'10px 14px',textAlign:'left',fontSize:'0.7rem',fontWeight:700,color:'#6b7280',textTransform:'uppercase',letterSpacing:'0.05em',borderBottom:'1px solid #e5e7eb'}}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {hospitals.map((h,i)=>(
                <tr key={h.id} style={{background:i%2===0?'white':'#fafafa'}}
                    onMouseEnter={e=>e.currentTarget.style.background='#f0fdf4'}
                    onMouseLeave={e=>e.currentTarget.style.background=i%2===0?'white':'#fafafa'}>
                  <td style={{padding:'10px 14px',borderBottom:'1px solid #f1f1f1'}}>
                    <div style={{fontWeight:700,fontSize:'0.875rem',color:'#111827'}}>{h.name}</div>
                    <div style={{fontSize:'0.75rem',color:'#6b7280',marginTop:2}}>{h.address}</div>
                    <div style={{fontSize:'0.68rem',color:'#9ca3af',marginTop:1}}>{h.latitude}, {h.longitude}</div>
                  </td>
                  <td style={{padding:'10px 14px',borderBottom:'1px solid #f1f1f1'}}>
                    <span style={{background:h.type==='private'?'#dcfce7':'#dbeafe',color:h.type==='private'?'#16a34a':'#1d4ed8',borderRadius:8,padding:'2px 8px',fontSize:'0.7rem',fontWeight:700,textTransform:'capitalize'}}>
                      {h.type}
                    </span>
                  </td>
                  <td style={{padding:'10px 14px',fontSize:'0.8rem',color:'#374151',borderBottom:'1px solid #f1f1f1'}}>{h.phone}</td>
                  <td style={{padding:'10px 14px',borderBottom:'1px solid #f1f1f1',textAlign:'center'}}>
                    {h.emergency
                      ? <I c="fa-circle-check" style={{color:'#16a34a',fontSize:'1rem'}}/>
                      : <I c="fa-circle-xmark" style={{color:'#d1d5db',fontSize:'1rem'}}/>}
                  </td>
                  <td style={{padding:'10px 14px',borderBottom:'1px solid #f1f1f1'}}>
                    <div style={{display:'flex',gap:4}}>
                      <button onClick={()=>setEditH({...h, services: Array.isArray(h.services)?h.services.join(', '):(typeof h.services==='string'?JSON.parse(h.services||'[]').join(', '):'')})}
                              style={{background:'#eff6ff',border:'1px solid #bfdbfe',color:'#1d4ed8',borderRadius:6,padding:'4px 8px',cursor:'pointer',fontSize:'0.75rem'}}>
                        <I c="fa-pen"/>
                      </button>
                      <button onClick={()=>setConfirmDel(h)}
                              style={{background:'#fef2f2',border:'1px solid #fca5a5',color:'#dc2626',borderRadius:6,padding:'4px 8px',cursor:'pointer',fontSize:'0.75rem'}}>
                        <I c="fa-trash"/>
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {hospitals.length===0&&<div style={{textAlign:'center',padding:'2rem',color:'#6b7280',fontSize:'0.875rem'}}>No hospitals found.</div>}
        </div>
      )}

      {editH !== null && (
        <Modal title={editH.id ? `Edit — ${editH.name}` : 'Add New Hospital'} onClose={()=>setEditH(null)}>
          <HospitalForm h={editH} saving={saving} msg={msg} onSave={saveHospital} onCancel={()=>setEditH(null)}/>
        </Modal>
      )}

      {confirmDel && (
        <Modal title="Delete Hospital" onClose={()=>setConfirmDel(null)}>
          <div style={{textAlign:'center'}}>
            <I c="fa-triangle-exclamation" style={{fontSize:'2.5rem',color:'#dc2626',marginBottom:12,display:'block'}}/>
            <p style={{fontSize:'0.875rem',color:'#374151',marginBottom:16}}>Delete <strong>{confirmDel.name}</strong>? This cannot be undone.</p>
            <div style={{display:'flex',gap:8,justifyContent:'center'}}>
              <button className="btn btn-ghost" onClick={()=>setConfirmDel(null)}>Cancel</button>
              <button className="btn btn-danger" onClick={()=>deleteH(confirmDel.id)}>
                <I c="fa-trash" style={{marginRight:6}}/>Delete
              </button>
            </div>
          </div>
        </Modal>
      )}
    </div>
  );
}

function HospitalForm({ h, saving, msg, onSave, onCancel }) {
  const [form, setForm] = useState({ ...h });
  const set = k => e => setForm(f=>({...f,[k]:e.target.type==='checkbox'?e.target.checked:e.target.value}));
  return (
    <div>
      {msg && <div className={`alert ${msg.includes('add')||msg.includes('upd')?'alert-success':'alert-error'}`} style={{marginBottom:'1rem'}}>{msg}</div>}
      <div className="form-group">
        <label className="form-label">Hospital Name *</label>
        <input className="form-input" value={form.name||''} onChange={set('name')} required placeholder="e.g. Kenyatta National Hospital"/>
      </div>
      <div className="form-group">
        <label className="form-label">Address</label>
        <input className="form-input" value={form.address||''} onChange={set('address')} placeholder="e.g. Hospital Rd, Upper Hill, Nairobi"/>
      </div>
      <div className="grid-2">
        <div className="form-group">
          <label className="form-label">Latitude *</label>
          <input type="number" step="any" className="form-input" value={form.latitude||''} onChange={set('latitude')} placeholder="-1.3048" required/>
        </div>
        <div className="form-group">
          <label className="form-label">Longitude *</label>
          <input type="number" step="any" className="form-input" value={form.longitude||''} onChange={set('longitude')} placeholder="36.8156" required/>
        </div>
      </div>
      <div style={{fontSize:'0.72rem',color:'#9ca3af',marginTop:-8,marginBottom:12}}>
        <I c="fa-circle-info" style={{marginRight:4}}/>Find coordinates at <a href="https://www.latlong.net/" target="_blank" rel="noreferrer" style={{color:'#16a34a'}}>latlong.net</a>
      </div>
      <div className="grid-2">
        <div className="form-group">
          <label className="form-label">Phone</label>
          <input className="form-input" value={form.phone||''} onChange={set('phone')} placeholder="+254 20 000 0000"/>
        </div>
        <div className="form-group">
          <label className="form-label">Type</label>
          <select className="form-input" value={form.type||'government'} onChange={set('type')}>
            {HOSPITAL_TYPES.map(t=><option key={t} value={t}>{t.charAt(0).toUpperCase()+t.slice(1)}</option>)}
          </select>
        </div>
      </div>
      <div className="form-group">
        <label className="form-label">Services <span style={{color:'#9ca3af',fontWeight:400}}>(comma-separated)</span></label>
        <input className="form-input" value={form.services||''} onChange={set('services')} placeholder="Emergency, Surgery, ICU, Maternity"/>
      </div>
      <div style={{display:'flex',alignItems:'center',gap:10,marginBottom:'1rem'}}>
        <input type="checkbox" id="emerg" checked={!!form.emergency} onChange={set('emergency')} style={{width:16,height:16,accentColor:'#16a34a'}}/>
        <label htmlFor="emerg" style={{fontSize:'0.875rem',fontWeight:500,cursor:'pointer'}}>24-hour Emergency Service</label>
      </div>
      <div style={{display:'flex',gap:8}}>
        <button className="btn btn-ghost" onClick={onCancel} style={{flex:1,justifyContent:'center'}}>Cancel</button>
        <button className="btn btn-primary" onClick={()=>onSave(form)} disabled={saving||!form.name||!form.latitude||!form.longitude} style={{flex:2,justifyContent:'center'}}>
          {saving?<><span className="spinner" style={{width:14,height:14}}/> Saving...</>:<><I c="fa-floppy-disk" style={{marginRight:6}}/>{form.id?'Save Changes':'Add Hospital'}</>}
        </button>
      </div>
    </div>
  );
}

// ── Deficiencies (read-only knowledge base view) ──────────────────────────────
function Deficiencies() {
  const totals = DEFICIENCY_LIST.reduce((a,d)=>({s:a.s+d.symptoms,f:a.f+d.foods}),{s:0,f:0});
  return (
    <div>
      <div style={{padding:'0.75rem 1rem',background:'#f0fdf4',border:'1px solid #bbf7d0',borderRadius:10,marginBottom:'1rem',fontSize:'0.82rem',color:'#15803d'}}>
        <I c="fa-circle-info" style={{marginRight:6}}/>The knowledge base is defined in <code>backend/ai_engine.py</code> and <code>frontend/src/engine/analyzer.js</code>. Edit those files to add or modify deficiencies.
      </div>
      <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fit,minmax(160px,1fr))',gap:10,marginBottom:'1rem'}}>
        {[
          {label:'Deficiencies',value:DEFICIENCY_LIST.length,color:'#16a34a',icon:'fa-list'},
          {label:'Total Symptoms Mapped',value:totals.s,color:'#0891b2',icon:'fa-stethoscope'},
          {label:'Food Recommendations',value:totals.f,color:'#d97706',icon:'fa-utensils'},
          {label:'Kenya Stats',value:DEFICIENCY_LIST.length,color:'#7c3aed',icon:'fa-flag'},
        ].map(c=>(
          <div key={c.label} className="card" style={{textAlign:'center',padding:'1rem'}}>
            <I c={c.icon} style={{fontSize:'1.4rem',color:c.color,marginBottom:6,display:'block'}}/>
            <div style={{fontSize:'1.5rem',fontWeight:800,fontFamily:'Fraunces,serif',color:c.color,lineHeight:1}}>{c.value}</div>
            <div style={{fontSize:'0.7rem',color:'#6b7280',fontWeight:600,marginTop:3}}>{c.label}</div>
          </div>
        ))}
      </div>
      <div className="card" style={{padding:0,overflow:'hidden'}}>
        <table style={{width:'100%',borderCollapse:'collapse'}}>
          <thead style={{background:'#f9fafb'}}>
            <tr>
              {['Deficiency','Kenya Prevalence','Symptoms','Foods','Status'].map(h=>(
                <th key={h} style={{padding:'10px 14px',textAlign:'left',fontSize:'0.7rem',fontWeight:700,color:'#6b7280',textTransform:'uppercase',letterSpacing:'0.05em',borderBottom:'1px solid #e5e7eb'}}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {DEFICIENCY_LIST.map((d,i)=>(
              <tr key={d.id} style={{background:i%2===0?'white':'#fafafa'}}>
                <td style={{padding:'12px 14px',borderBottom:'1px solid #f1f1f1'}}>
                  <div style={{display:'flex',alignItems:'center',gap:8}}>
                    <div style={{width:28,height:28,borderRadius:8,background:`${d.color}15`,display:'flex',alignItems:'center',justifyContent:'center',flexShrink:0}}>
                      <I c={d.icon} style={{color:d.color,fontSize:'0.85rem'}}/>
                    </div>
                    <span style={{fontWeight:700,fontSize:'0.875rem',color:d.color}}>{d.name}</span>
                  </div>
                </td>
                <td style={{padding:'12px 14px',fontSize:'0.78rem',color:'#6b7280',borderBottom:'1px solid #f1f1f1',maxWidth:180}}>{d.stat}</td>
                <td style={{padding:'12px 14px',fontSize:'0.875rem',fontWeight:600,color:'#374151',borderBottom:'1px solid #f1f1f1'}}>{d.symptoms}</td>
                <td style={{padding:'12px 14px',fontSize:'0.875rem',fontWeight:600,color:'#374151',borderBottom:'1px solid #f1f1f1'}}>{d.foods}</td>
                <td style={{padding:'12px 14px',borderBottom:'1px solid #f1f1f1'}}>
                  <span style={{background:'#f0fdf4',color:'#16a34a',borderRadius:8,padding:'2px 8px',fontSize:'0.7rem',fontWeight:700,display:'flex',alignItems:'center',gap:4,width:'fit-content'}}>
                    <I c="fa-circle-check"/>Active
                  </span>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

